def detect_flakiness(func, n_runs=10):
    try:
        results = [func() for _ in range(n_runs)]
        for i in range(len(results)):
            for j in range(i + 1, len(results)):
                if results[i] != results[j] or results[i] is not results[j]:
                    return True
        return False
    except Exception:
        return True
